// Extra letters for expanded Dear Ethicist question bank
// Generated for SQND research — 80 additional probe letters
window.DEAR_ETHICIST_EXTRA = [
// =======================================================================
// CATEGORY 1: DIGITAL LIFE (10 letters)
// =======================================================================
{id:"digital_streaming_password",subject:"My ex still uses my Netflix password",body:"Dear Ethicist,\n\nWhen we were dating, I shared my Netflix password with my partner. We broke up four months ago but I noticed they're still using it daily. They never asked if they could keep using it, and I never told them to stop.\n\nDo I have a right to change it without warning? Or does our past relationship create some grace period I should honor?",signoff:"STREAMING SOLO IN SACRAMENTO",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Ex",role:"ex_partner",expected:"N"}],questions:["Do I have a right to change the password without warning?","Does the past relationship create a grace period?"]},
{id:"digital_photo_consent",subject:"Friend posted our group photo without asking",body:"Dear Ethicist,\n\nMy friend posted a group photo from last weekend's barbecue on Instagram without asking anyone's permission. I look terrible in it and I'm tagged. When I asked her to take it down, she said it's her photo and she can post what she wants.\n\nDoes she have an obligation to remove it if I ask? Do I have a right to control photos of myself on someone else's account?",signoff:"UNFILTERED IN FRESNO",parties:[{name:"Friend",role:"poster",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does she have an obligation to remove it?","Do I have a right to control photos of myself?"]},
{id:"digital_partner_phone",subject:"I looked through my partner's phone",body:"Dear Ethicist,\n\nI had a gut feeling something was off, so while my partner was in the shower I looked through their text messages. I didn't find anything incriminating, but now I feel guilty. My partner doesn't know I did this.\n\nDid I violate an obligation by snooping? Does my partner have a right to phone privacy even in a committed relationship?",signoff:"GUILTY THUMBS IN TAMPA",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Partner",role:"partner",expected:"C"}],questions:["Did I violate an obligation by snooping?","Does my partner have a right to phone privacy in a relationship?"]},
{id:"digital_ai_essay",subject:"I used ChatGPT for my college essay",body:"Dear Ethicist,\n\nI used an AI chatbot to write the first draft of my college application essay, then edited it heavily to sound like me. My counselor says the essay is great and very personal. The application doesn't specifically ban AI tools.\n\nDo I have an obligation to disclose that I used AI? Does the admissions committee have a right to know my process?",signoff:"PROMPTED IN PRINCETON",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Admissions",role:"institution",expected:"C"}],questions:["Do I have an obligation to disclose AI use?","Does the admissions committee have a right to know?"]},
{id:"digital_ghosting",subject:"I ghosted someone after three dates",body:"Dear Ethicist,\n\nI went on three dates with someone from a dating app. They were perfectly nice but I just wasn't feeling it. Instead of having an awkward conversation, I stopped responding to their messages. They've sent four texts asking if I'm okay.\n\nDo I owe them an explanation? Do they have a right to a proper rejection after three dates?",signoff:"DISAPPEARED IN DENVER",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Date",role:"romantic_interest",expected:"C"}],questions:["Do I owe them an explanation?","Do they have a right to a proper rejection?"]},
{id:"digital_wifi_stealing",subject:"I've been using my neighbor's open WiFi",body:"Dear Ethicist,\n\nMy neighbor's WiFi network has no password. I've been using it for three months instead of paying for my own internet. They probably don't even know. It's not like I'm slowing it down much.\n\nIs using an unsecured network without permission wrong? Does my neighbor have a claim against me even though they didn't secure it?",signoff:"CONNECTED IN COLUMBUS",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Neighbor",role:"network_owner",expected:"C"}],questions:["Is using an unsecured network without permission wrong?","Does the neighbor have a claim even though they didn't secure it?"]},
{id:"digital_cyberbully_witness",subject:"I saw my coworker being cyberbullied",body:"Dear Ethicist,\n\nI stumbled across a group chat where several people from our office are mocking a quiet coworker, sharing unflattering photos of her and making cruel jokes. I'm not part of the bullying, but I was added to the chat by mistake and saw everything.\n\nDo I have an obligation to tell my coworker or report this to HR? Or am I free to stay out of it since I'm not involved?",signoff:"BYSTANDER IN BOISE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Coworker",role:"victim",expected:"C"}],questions:["Do I have an obligation to report this?","Am I free to stay out of it?"]},
{id:"digital_location_tracking",subject:"I track my teenage daughter's location",body:"Dear Ethicist,\n\nI installed a location-tracking app on my 16-year-old daughter's phone without telling her. She recently found out and is furious, saying I violated her trust. I say I'm her parent and it's my job to keep her safe.\n\nDo I have a right to track my minor child? Does she have a legitimate claim to privacy at 16?",signoff:"HELICOPTER IN HOUSTON",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Daughter",role:"child",expected:"N"}],questions:["Do I have a right to track my minor child?","Does a 16-year-old have a claim to location privacy?"]},
{id:"digital_fake_review",subject:"Restaurant owner asked me to post a fake review",body:"Dear Ethicist,\n\nMy friend owns a small restaurant that's been getting unfair one-star reviews from a competitor. She asked me to post a glowing five-star review even though I've never eaten there, to counterbalance the fake negatives.\n\nDo I have an obligation to help my friend fight unfair reviews? Or do potential customers have a right to only see honest reviews?",signoff:"FIVE STARS IN PHOENIX",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Friend",role:"business_owner",expected:"N"},{name:"Customers",role:"public",expected:"C"}],questions:["Do I have an obligation to help fight unfair reviews?","Do customers have a right to only honest reviews?"]},
{id:"digital_dead_persons_account",subject:"Should I log into my late mother's Facebook?",body:"Dear Ethicist,\n\nMy mother passed away last month. I know her Facebook password and I want to log in to download her photos and read her messages to me. My brother says it's an invasion of her privacy, even in death.\n\nDo I have a right to access her account? Does a deceased person still have a claim to digital privacy?",signoff:"GRIEVING IN GALVESTON",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Mother",role:"deceased",expected:null}],questions:["Do I have a right to access her account?","Does a deceased person have a claim to digital privacy?"]},
// =======================================================================
// CATEGORY 2: MEDICAL/HEALTH (8 letters)
// =======================================================================
{id:"medical_treatment_refusal",subject:"My father refuses cancer treatment",body:"Dear Ethicist,\n\nMy 72-year-old father has been diagnosed with treatable cancer but refuses chemotherapy. He says he's lived a full life and doesn't want to spend his remaining time sick from treatment. My mother and I are devastated.\n\nDoes he have the liberty to refuse treatment? Or does his obligation to his family override his personal choice?",signoff:"DESPERATE IN DETROIT",parties:[{name:"Father",role:"patient",expected:"L"},{name:"You",role:"letter_writer",expected:"N"}],questions:["Does he have the liberty to refuse treatment?","Does his obligation to family override his choice?"]},
{id:"medical_genetic_info",subject:"My genetic test revealed a family secret",body:"Dear Ethicist,\n\nI did a consumer genetic test and discovered I carry a gene for Huntington's disease. This means one of my parents has it too, and my siblings are at risk. My parents don't want me to tell my siblings because they 'don't want to worry anyone.'\n\nDo my siblings have a right to know about their genetic risk? Am I obligated to tell them despite my parents' wishes?",signoff:"CODED IN CAROLINA",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Siblings",role:"family",expected:"C"}],questions:["Do my siblings have a right to know?","Am I obligated to tell them despite my parents' wishes?"]},
{id:"medical_workplace_illness",subject:"Coworker came to work with the flu",body:"Dear Ethicist,\n\nMy coworker came into the office clearly sick with the flu because she said she can't afford to miss work. She sits three feet from me and I'm immunocompromised. Our boss doesn't seem to care.\n\nDoes my coworker have an obligation to stay home? Do I have a right to a safe workplace, or is she free to come in if she needs the money?",signoff:"MASKING IN MILWAUKEE",parties:[{name:"Coworker",role:"sick_worker",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does my coworker have an obligation to stay home?","Do I have a right to a safe workplace?"]},
{id:"medical_prescription_sharing",subject:"Friend asked for one of my Adderall",body:"Dear Ethicist,\n\nMy friend has a big exam tomorrow and asked if I could give her one of my Adderall pills. She says she just needs it this once to focus. I have a legitimate prescription and plenty of pills.\n\nDo I have an obligation to refuse, since sharing prescriptions is illegal? Or am I free to help a friend in need?",signoff:"PRESCRIBED IN PORTLAND",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"requester",expected:"N"}],questions:["Do I have an obligation to refuse?","Am I free to help a friend in need?"]},
{id:"medical_vaccination_school",subject:"My neighbor won't vaccinate her kids",body:"Dear Ethicist,\n\nMy neighbor refuses to vaccinate her children, citing personal beliefs. Her unvaccinated kids play daily with my toddler, who is too young to be fully vaccinated. When I raised my concern, she said it's her right as a parent.\n\nDoes she have the liberty to make this choice for her children? Do I have a right to demand she keep her unvaccinated kids away from mine?",signoff:"IMMUNIZED IN INDIANAPOLIS",parties:[{name:"Neighbor",role:"anti_vax_parent",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does she have the liberty to not vaccinate?","Do I have a right to protect my child from exposure?"]},
{id:"medical_error_disclosure",subject:"My doctor made a mistake and won't admit it",body:"Dear Ethicist,\n\nDuring a routine procedure, my doctor nicked something he shouldn't have, requiring an extra week of recovery. When I asked what happened, he was evasive. A nurse later told me privately that he made an error.\n\nDoes my doctor have an obligation to disclose his mistake? Do I have a right to a full and honest explanation of what happened to my body?",signoff:"RECOVERING IN RALEIGH",parties:[{name:"Doctor",role:"physician",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does my doctor have an obligation to disclose the mistake?","Do I have a right to a full explanation?"]},
{id:"medical_mental_health_secret",subject:"My friend told me she's suicidal",body:"Dear Ethicist,\n\nMy friend confided that she's been having suicidal thoughts. She made me promise not to tell anyone, saying she'd never trust me again if I did. But I'm terrified she might actually hurt herself.\n\nAm I obligated to break her confidence and tell someone who can help? Does her right to privacy yield when her life is at stake?",signoff:"SCARED IN SAVANNAH",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"at_risk",expected:"C"}],questions:["Am I obligated to break her confidence?","Does her right to privacy yield when her life is at stake?"]},
{id:"medical_organ_donor",subject:"Family disagrees about deceased brother's organs",body:"Dear Ethicist,\n\nMy brother died unexpectedly. He was a registered organ donor, but my parents are refusing to allow organ harvesting because they want him 'whole' for the funeral. The hospital says the family can override the donor card.\n\nDo my parents have the right to override my brother's wishes? Or does his registered decision create an obligation they must honor?",signoff:"TORN IN TUCSON",parties:[{name:"Parents",role:"next_of_kin",expected:"O"},{name:"Brother",role:"deceased_donor",expected:"C"}],questions:["Do my parents have the right to override his wishes?","Does his donor registration create a binding obligation?"]},
// =======================================================================
// CATEGORY 3: COMMUNITY/CIVIC (8 letters)
// =======================================================================
{id:"civic_found_wallet",subject:"I found a wallet with $400 in it",body:"Dear Ethicist,\n\nI found a wallet in a parking lot containing $400 cash, credit cards, and a driver's license. The ID shows an address twenty minutes away. I could easily return it, but I'm also behind on rent and that $400 would really help.\n\nDo I have an obligation to return the wallet and all its contents? Does the owner have a right to expect a stranger's honesty?",signoff:"TEMPTED IN TOPEKA",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Owner",role:"wallet_owner",expected:"C"}],questions:["Do I have an obligation to return everything?","Does the owner have a right to expect a stranger's honesty?"]},
{id:"civic_shoplifting_witness",subject:"I saw a mother shoplifting baby formula",body:"Dear Ethicist,\n\nI watched a young mother slip a can of baby formula into her diaper bag at the grocery store. She looked exhausted and desperate. A security guard was heading her way and glanced at me, clearly asking if I saw anything.\n\nDo I have an obligation to report what I saw? Or am I free to look the other way given the circumstances?",signoff:"WITNESS IN WICHITA",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Mother",role:"shoplifter",expected:null}],questions:["Do I have an obligation to report what I saw?","Am I free to look the other way?"]},
{id:"civic_double_charged",subject:"The store accidentally gave me too much change",body:"Dear Ethicist,\n\nThe cashier at my local hardware store gave me $50 too much in change. I didn't notice until I got home. It's a small family-owned shop and I know they operate on thin margins.\n\nDo I have an obligation to go back and return the money? Does the shop have a right to expect me to correct their mistake?",signoff:"OVERPAID IN OMAHA",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Shop",role:"business",expected:"C"}],questions:["Do I have an obligation to return the extra money?","Does the shop have a right to expect honesty?"]},
{id:"civic_seat_priority",subject:"Teenager wouldn't give up bus seat for elderly woman",body:"Dear Ethicist,\n\nI was on the bus when an elderly woman with a cane boarded. A teenager was sitting in the priority seating, headphones in, eyes on his phone. He saw her and didn't move. Nobody said anything, so I gave up my regular seat instead.\n\nDid the teenager have an obligation to give up the priority seat? Did the elderly woman have a right to expect it?",signoff:"STANDING IN STAMFORD",parties:[{name:"Teenager",role:"seated_passenger",expected:"O"},{name:"Elderly woman",role:"standing_passenger",expected:"C"}],questions:["Did the teenager have an obligation to give up the seat?","Did the elderly woman have a right to expect it?"]},
{id:"civic_hoa_fence",subject:"HOA says my garden violates the rules",body:"Dear Ethicist,\n\nI planted a vegetable garden in my front yard. My HOA says it violates their aesthetic guidelines and I have 30 days to remove it. I think growing food on my own property is a fundamental right. The HOA rules were in place when I bought the house.\n\nDoes the HOA have a right to dictate what I grow on my property? Am I obligated to follow rules I voluntarily agreed to, even if I think they're absurd?",signoff:"GARDENING IN GLENDALE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"HOA",role:"authority",expected:"C"}],questions:["Does the HOA have a right to dictate what I grow?","Am I obligated to follow rules I agreed to?"]},
{id:"civic_jury_duty",subject:"I lied to get out of jury duty",body:"Dear Ethicist,\n\nI was called for jury duty during our busiest season at work. During selection, I exaggerated a bias I don't really have to get dismissed. My boss was relieved, but I feel like I shirked a civic duty.\n\nDid I have an obligation to serve honestly? Does the justice system have a right to my truthful participation?",signoff:"DISMISSED IN DALLAS",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Justice system",role:"institution",expected:"C"}],questions:["Did I have an obligation to serve honestly?","Does the justice system have a right to my truthful participation?"]},
{id:"civic_noise_party",subject:"My block party is annoying one neighbor",body:"Dear Ethicist,\n\nOur neighborhood throws an annual block party that everyone loves except one family. They've complained about the noise, the blocked street, and kids running through their yard. We have a permit and stay within noise ordinance hours.\n\nDoes the one dissenting family have a right to object? Are we obligated to accommodate them even though we're following all the rules?",signoff:"PARTYING ON PINE STREET",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Neighbor",role:"dissenter",expected:"N"}],questions:["Does the dissenting family have a right to object?","Are we obligated to accommodate them?"]},
{id:"civic_panhandler",subject:"The same panhandler asks me every day",body:"Dear Ethicist,\n\nEvery morning the same person asks me for money outside the coffee shop. I've given a few times, but now I feel pressured every single day. When I walk past without giving, they say 'God bless you anyway' in a tone that makes me feel awful.\n\nDo I have any obligation to give? Does a repeated interaction create a different kind of duty than a one-time encounter?",signoff:"COMMUTING WITH GUILT",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Panhandler",role:"requester",expected:"N"}],questions:["Do I have any obligation to give?","Does repeated interaction create a duty?"]},
// =======================================================================
// CATEGORY 4: WORKPLACE EXTENDED (8 letters)
// =======================================================================
{id:"work_boss_credit",subject:"My boss presented my work as her own",body:"Dear Ethicist,\n\nI spent three weeks developing a proposal. In the executive meeting, my boss presented it as her own idea without mentioning my name once. When I confronted her, she said 'everything the team does reflects on me as the leader.'\n\nDoes she have an obligation to credit my work? Do I have a right to recognition, or does the organizational hierarchy mean her claim is legitimate?",signoff:"UNCREDITED IN URBANA",parties:[{name:"Boss",role:"manager",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does she have an obligation to credit my work?","Do I have a right to recognition?"]},
{id:"work_training_replacement",subject:"They want me to train the person replacing me",body:"Dear Ethicist,\n\nI was told my position is being eliminated in 60 days. During that time, they want me to train my replacement — a younger employee they're paying less. My severance package is contingent on 'full cooperation during transition.'\n\nAm I obligated to train my replacement? Does the company have a right to demand this, or is tying it to severance coercive?",signoff:"OBSOLETE IN ORLANDO",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Company",role:"employer",expected:"C"}],questions:["Am I obligated to train my replacement?","Does tying it to severance make this coercive?"]},
{id:"work_noncompete",subject:"My non-compete blocks my dream job",body:"Dear Ethicist,\n\nI signed a non-compete agreement when I took this job. Now a competitor has offered me my dream position at double the salary. The non-compete is probably unenforceable in my state, but my current employer says they'll sue anyway.\n\nAm I obligated to honor an agreement I signed even if it's legally dubious? Does my employer have a right to enforce a potentially unfair contract?",signoff:"COMPETING IN KANSAS CITY",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Employer",role:"current_employer",expected:null}],questions:["Am I obligated to honor the non-compete?","Does my employer have a right to enforce a dubious contract?"]},
{id:"work_lying_to_clients",subject:"Boss told me to mislead a client",body:"Dear Ethicist,\n\nMy boss instructed me to tell a client that their project is 'on track' when we both know it's three weeks behind. He says we'll catch up and there's no point in worrying them. The client is making business decisions based on our timeline.\n\nDo I have an obligation to tell the client the truth? Or does loyalty to my employer override the client's right to accurate information?",signoff:"FIBBING IN PHOENIX",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Client",role:"customer",expected:"C"}],questions:["Do I have an obligation to tell the client the truth?","Does employer loyalty override client honesty?"]},
{id:"work_fake_credentials",subject:"I discovered my colleague faked her degree",body:"Dear Ethicist,\n\nI accidentally discovered that my colleague listed a master's degree on her resume that she never completed. She's been at the company five years and is excellent at her job. Reporting her would almost certainly get her fired.\n\nDo I have an obligation to report this? Does the company have a right to know, even though her actual performance is outstanding?",signoff:"CREDENTIALED IN CHARLOTTE",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Colleague",role:"coworker",expected:null}],questions:["Do I have an obligation to report this?","Does the company have a right to know?"]},
{id:"work_sick_day_lie",subject:"I called in sick to go to a concert",body:"Dear Ethicist,\n\nI called in sick last Friday to attend a concert. I had PTO available but my request was denied because of a project deadline. The project wasn't urgent — my boss just doesn't like approving time off. A coworker saw my concert photos on social media.\n\nDid I violate an obligation to my employer? Does my boss have a right to demand I work when PTO was unreasonably denied?",signoff:"ROCKING IN RICHMOND",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Boss",role:"employer",expected:"C"}],questions:["Did I violate an obligation to my employer?","Does unreasonable PTO denial change the equation?"]},
{id:"work_salary_discussion",subject:"HR says I can't discuss my salary",body:"Dear Ethicist,\n\nI found out a male colleague with the same title and less experience makes $15,000 more than me. When I told HR, they said salary discussions between employees violate company policy. I know federal law protects salary discussions.\n\nDoes the company have a right to prohibit salary discussions? Do I have a right to share and seek this information?",signoff:"UNDERPAID IN AUSTIN",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Company",role:"employer",expected:"N"}],questions:["Does the company have a right to prohibit salary discussions?","Do I have a right to share salary information?"]},
{id:"work_remote_monitoring",subject:"My company installed monitoring software",body:"Dear Ethicist,\n\nMy company installed software that takes screenshots of my laptop every five minutes during work hours. I work from home and sometimes personal things are on screen — my bank account, medical portal, private messages. They say monitoring is their right since it's a company laptop.\n\nDoes my employer have a right to this level of surveillance? Do I have a claim to some privacy even on a work device during work hours?",signoff:"WATCHED IN WILMINGTON",parties:[{name:"You",role:"letter_writer",expected:"C"},{name:"Employer",role:"company",expected:"O"}],questions:["Does my employer have a right to this surveillance?","Do I have a claim to some privacy on a work device?"]},
// =======================================================================
// CATEGORY 5: FAMILY EXTENDED (8 letters)
// =======================================================================
{id:"family_inlaws_advice",subject:"My mother-in-law won't stop giving parenting advice",body:"Dear Ethicist,\n\nMy mother-in-law critiques every parenting decision I make — from what I feed my kids to how I discipline them. My husband says she means well and I should just smile and nod. Last week she signed my son up for a sports league without asking me.\n\nDoes she have any right to influence how I raise my children? Am I obligated to tolerate her input for the sake of family peace?",signoff:"OVERRULED IN OKLAHOMA",parties:[{name:"Mother-in-law",role:"grandparent",expected:"N"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does she have any right to influence my parenting?","Am I obligated to tolerate her input?"]},
{id:"family_estranged_parent",subject:"My estranged father wants back in my life",body:"Dear Ethicist,\n\nMy father walked out when I was eight and made zero effort to contact me for 20 years. Now he's sick and wants to 'reconnect.' My mother, who raised me alone, is heartbroken that I'm even considering it.\n\nDoes my father have any right to a relationship with me now? Am I obligated to give him a chance, or am I free to maintain the distance he created?",signoff:"ABANDONED IN ATLANTA",parties:[{name:"Father",role:"estranged_parent",expected:"N"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does my father have any right to reconnect?","Am I obligated to give him a chance?"]},
{id:"family_hosting_expectations",subject:"My family expects me to host every holiday",body:"Dear Ethicist,\n\nBecause I have the biggest house, my family expects me to host Thanksgiving, Christmas, Easter, and Fourth of July. Nobody offers to help cook, clean, or contribute financially. When I suggested rotating hosts, my aunt said 'but your house is perfect for it.'\n\nDo I have an obligation to keep hosting? Does my family have a right to expect this just because I have the space?",signoff:"EXHAUSTED ENTERTAINER IN ERIE",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Family",role:"relatives",expected:"N"}],questions:["Do I have an obligation to keep hosting?","Does my family have a right to expect this?"]},
{id:"family_playing_favorites",subject:"My parents clearly favor my sister",body:"Dear Ethicist,\n\nMy parents paid for my sister's entire wedding ($40,000) but told me they could only contribute $5,000 to mine because 'times are tight.' Yet they just renovated their kitchen. My sister says I'm being petty and should be grateful for anything.\n\nDo I have a right to equal treatment from my parents? Do they have an obligation to be fair, or is it their money to distribute as they please?",signoff:"SECOND FAVORITE IN SAN DIEGO",parties:[{name:"You",role:"letter_writer",expected:"C"},{name:"Parents",role:"parents",expected:"O"}],questions:["Do I have a right to equal treatment?","Do they have an obligation to be fair?"]},
{id:"family_adult_child_home",subject:"My 28-year-old son won't move out",body:"Dear Ethicist,\n\nMy 28-year-old son still lives at home. He has a decent job but says he's 'saving money.' He doesn't pay rent, rarely does chores, and his girlfriend practically lives here too. When I bring up moving out, he says I'm being unsupportive.\n\nDo I have a right to ask him to leave? Does he have any claim to continue living here as my adult child?",signoff:"FULL HOUSE IN FARGO",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Son",role:"adult_child",expected:"N"}],questions:["Do I have a right to ask him to leave?","Does he have any claim to continue living here?"]},
{id:"family_sibling_caretaker",subject:"My sister dumped her kids on me for the summer",body:"Dear Ethicist,\n\nMy sister asked if her kids could stay with me for 'a week or two' this summer while she sorted out some things. It's been six weeks. She keeps extending the timeline and gets angry when I bring up an end date. I love my nieces but this isn't what I agreed to.\n\nDoes she have an obligation to take her children back on the original timeline? Do I have a right to set a firm deadline even though the kids are happy here?",signoff:"AUNT-TURNED-PARENT IN ANNAPOLIS",parties:[{name:"Sister",role:"parent",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does she have an obligation to take her kids back?","Do I have a right to set a firm deadline?"]},
{id:"family_wedding_invite",subject:"My cousin didn't invite my partner",body:"Dear Ethicist,\n\nMy cousin's wedding invitation was addressed only to me, not to my partner of five years. When I asked, she said the venue is small and she had to cut somewhere. But other cousins got plus-ones for people they've dated for months.\n\nDoes my cousin have an obligation to invite my long-term partner? Or is she free to set her guest list however she wants?",signoff:"PLUS NONE IN PITTSBURGH",parties:[{name:"Cousin",role:"bride",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does my cousin have an obligation to invite my partner?","Is she free to set her guest list however she wants?"]},
{id:"family_grandparent_religion",subject:"My parents are teaching my kid religion against my wishes",body:"Dear Ethicist,\n\nI'm raising my daughter secular. My parents, who are devoutly religious, have been taking her to church during their babysitting days and teaching her prayers. When I confronted them, they said they have a 'grandparent's right' to share their faith.\n\nDo my parents have any right to introduce religion to my child? Am I obligated to let them express their beliefs, or do I have full authority over my daughter's upbringing?",signoff:"SECULAR IN SALT LAKE",parties:[{name:"You",role:"letter_writer",expected:"C"},{name:"Parents",role:"grandparents",expected:"O"}],questions:["Do my parents have a right to share their faith with my child?","Do I have full authority over my daughter's upbringing?"]},
// =======================================================================
// CATEGORY 6: AUTHORITY/STATUS BIAS (8 letters)
// =======================================================================
{id:"bias_rich_friend",subject:"Wealthy friend expects me to always accommodate her",body:"Dear Ethicist,\n\nMy friend is extremely wealthy. She always picks expensive restaurants and then acts surprised when I suggest splitting the bill is hard for me. Last week she asked me to change my vacation plans to align with hers, saying 'it's not like the flight change fee is a big deal.'\n\nDoes her wealth give her any right to expect me to accommodate her preferences? Am I obligated to just go along because she's used to getting her way?",signoff:"BROKE IN BEVERLY HILLS",parties:[{name:"Friend",role:"wealthy_friend",expected:"N"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does her wealth give her a right to expect accommodation?","Am I obligated to go along with her preferences?"]},
{id:"bias_professor_favor",subject:"Professor asked me to babysit in exchange for a recommendation",body:"Dear Ethicist,\n\nMy professor mentioned she needs a babysitter on weekends. She then told me she'd be 'happy to write a strong recommendation letter' for grad school. The implication felt clear. I need that letter, but this feels like a quid pro quo.\n\nDoes she have a right to ask personal favors of a student? Am I obligated to comply because of the power she holds over my future?",signoff:"GRADING THE SITUATION IN GAINESVILLE",parties:[{name:"Professor",role:"authority",expected:"O"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does she have a right to ask personal favors?","Am I obligated to comply given the power dynamic?"]},
{id:"bias_landlord_boundaries",subject:"My landlord keeps dropping by unannounced",body:"Dear Ethicist,\n\nMy landlord lives next door and treats my rental like an extension of his property. He drops by unannounced to 'check on things,' lets himself in when I'm at work, and once rearranged furniture he thought was blocking a vent. My lease says 24-hour notice for entry.\n\nDoes my landlord have any right to enter my home without notice? Am I obligated to be accommodating because he's been a good landlord otherwise?",signoff:"NO BOUNDARIES IN NASHVILLE",parties:[{name:"You",role:"letter_writer",expected:"C"},{name:"Landlord",role:"property_owner",expected:"O"}],questions:["Does my landlord have a right to enter without notice?","Am I obligated to accommodate his behavior?"]},
{id:"bias_celebrity_neighbor",subject:"Famous neighbor expects us to protect his privacy",body:"Dear Ethicist,\n\nA well-known actor moved onto our street. He asked all the neighbors to sign informal agreements not to post photos or mention his address on social media. Most people signed, but I didn't. Now he's annoyed with me.\n\nDoes he have a right to demand our silence about his location? Am I obligated to protect his privacy just because he's famous?",signoff:"STARSTRUCK IN SANTA MONICA",parties:[{name:"Celebrity",role:"neighbor",expected:"N"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does he have a right to demand silence about his location?","Am I obligated to protect his privacy?"]},
{id:"bias_police_stop",subject:"Officer asked to search my car without probable cause",body:"Dear Ethicist,\n\nI was pulled over for a broken taillight. The officer asked if he could search my car. I have nothing to hide, but the request felt intrusive. When I hesitated, he said 'if you have nothing to hide, you have nothing to worry about.'\n\nDid I have the liberty to refuse the search? Does the officer have a right to expect compliance just because he asked politely?",signoff:"PULLED OVER IN PORTLAND",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Officer",role:"authority",expected:"N"}],questions:["Did I have the liberty to refuse the search?","Does the officer have a right to expect compliance?"]},
{id:"bias_doctor_authority",subject:"Doctor dismissed my symptoms",body:"Dear Ethicist,\n\nI told my doctor about persistent symptoms I've been experiencing. Without running any tests, she said it was 'probably just stress' and to come back if it gets worse. I'm not a doctor, but I feel something is genuinely wrong.\n\nDo I have a right to demand specific tests? Does my doctor have an obligation to take my concerns seriously even if her expertise says otherwise?",signoff:"DISMISSED IN DULUTH",parties:[{name:"You",role:"letter_writer",expected:"C"},{name:"Doctor",role:"physician",expected:"O"}],questions:["Do I have a right to demand specific tests?","Does my doctor have an obligation to take my concerns seriously?"]},
{id:"bias_teacher_grade",subject:"Teacher changed my daughter's grade after I complained",body:"Dear Ethicist,\n\nMy daughter received a B+ on a paper she worked incredibly hard on. I emailed the teacher expressing my disappointment. The next day, the grade was changed to an A-. I'm now uncomfortable because I didn't ask for a grade change — I just wanted to understand the rubric.\n\nDid the teacher have an obligation to maintain the original grade? Did my inquiry create inappropriate pressure even though I didn't intend it?",signoff:"GRADED IN GREENVILLE",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Teacher",role:"educator",expected:null}],questions:["Did the teacher have an obligation to maintain the grade?","Did my inquiry create inappropriate pressure?"]},
{id:"bias_elder_authority",subject:"Grandfather insists on driving despite failing eyesight",body:"Dear Ethicist,\n\nMy 87-year-old grandfather has failing eyesight but insists on driving. He's had two minor fender benders this year. When we try to take his keys, he gets furious and says we're 'treating him like a child.' He's a proud man who values his independence above all.\n\nDo we have an obligation to stop him from driving? Does he have a right to make his own choices about his mobility, even if it puts others at risk?",signoff:"KEYHOLDER IN KENTUCKY",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Grandfather",role:"elder",expected:"N"}],questions:["Do we have an obligation to stop him?","Does he have a right to make his own choices about driving?"]},
// =======================================================================
// CATEGORY 7: TEMPORAL BIAS (8 letters)
// =======================================================================
{id:"temporal_decade_promise",subject:"Friend is cashing in a 10-year-old promise",body:"Dear Ethicist,\n\nTen years ago in college, I drunkenly told my roommate I'd help him start a business someday. He's now showing up with a business plan and reminding me of my 'promise.' I have a family, a mortgage, and zero interest in this venture.\n\nDoes a decade-old casual promise carry any weight? Does he have a right to hold me to something said over beers in a dorm room?",signoff:"PLEDGED IN A PAST LIFE",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Friend",role:"former_roommate",expected:"N"}],questions:["Does a decade-old casual promise carry any weight?","Does he have a right to hold me to it?"]},
{id:"temporal_childhood_debt",subject:"Childhood friend says I owe her from when we were 12",body:"Dear Ethicist,\n\nWhen we were twelve, my friend Sarah lent me $20 to buy a video game. She recently brought it up at a dinner party, saying I never paid her back and that with 'interest' I owe her $50. She claims she's joking, but she's brought it up three times now.\n\nDoes a debt from childhood still stand? Does Sarah have any legitimate claim to money lent between 12-year-olds?",signoff:"INDEBTED SINCE MIDDLE SCHOOL",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Sarah",role:"childhood_friend",expected:"N"}],questions:["Does a debt from childhood still stand?","Does Sarah have any legitimate claim?"]},
{id:"temporal_promise_deceased",subject:"I promised my dying grandmother I'd become a doctor",body:"Dear Ethicist,\n\nWhen my grandmother was dying, she asked me to promise I'd become a doctor. I was 16 and said yes. I'm now 24, in art school, and happy. My family says I'm 'breaking a sacred promise to the dead.'\n\nAm I obligated to honor a promise made to a dying relative when I was a teenager? Does my grandmother's memory have a claim on my life choices?",signoff:"PAINTING INSTEAD OF PRESCRIBING",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Grandmother",role:"deceased",expected:"N"}],questions:["Am I obligated to honor a deathbed promise?","Does her memory have a claim on my life choices?"]},
{id:"temporal_forgotten_promise_found",subject:"Found an old text where I promised to help",body:"Dear Ethicist,\n\nWhile scrolling through old messages, I found a text from two years ago where I enthusiastically promised my friend I'd help her move 'whenever she's ready.' She never brought it up again, and I completely forgot. She's now moving next month.\n\nIf she asks, am I still bound by this forgotten promise? Does a promise I don't remember making still create an obligation?",signoff:"SCROLLING THROUGH REGRET",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Friend",role:"friend",expected:null}],questions:["Am I still bound by a forgotten promise?","Does a promise I don't remember create an obligation?"]},
{id:"temporal_expired_offer",subject:"I said 'anytime' five years ago",body:"Dear Ethicist,\n\nFive years ago, when a former coworker was going through a divorce, I said 'if you ever need a place to stay, my door is always open.' She just called asking to move into my spare room. I barely know her anymore and my life circumstances have completely changed.\n\nDoes an open-ended offer expire? Does she have a right to take me up on something I said half a decade ago?",signoff:"OPEN DOOR POLICY EXPIRED",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Former coworker",role:"acquaintance",expected:"N"}],questions:["Does an open-ended offer expire?","Does she have a right to take me up on this?"]},
{id:"temporal_statute_of_apology",subject:"Ex-bully wants to apologize after 20 years",body:"Dear Ethicist,\n\nThe person who bullied me mercilessly in middle school found me on social media and sent a long, seemingly sincere apology. They say making amends is part of their recovery process. I have no interest in engaging.\n\nDo they have a right to be heard? Am I obligated to accept or even acknowledge their apology? Or am I free to ignore them?",signoff:"UNBOTHERED IN BOULDER",parties:[{name:"Former bully",role:"apologizer",expected:"N"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Do they have a right to be heard?","Am I obligated to acknowledge their apology?"]},
{id:"temporal_inheritance_promise",subject:"Dad promised the house to me before he got remarried",body:"Dear Ethicist,\n\nBefore my father remarried, he told me the family house would go to me since I grew up there. Now his new wife wants to sell it. Dad says his circumstances changed and the promise no longer applies.\n\nDoes his earlier promise create a lasting obligation? Do I have a right to the house based on what he said before his marriage?",signoff:"HOMELESS HEIR IN HARTFORD",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Father",role:"parent",expected:null}],questions:["Does his earlier promise create a lasting obligation?","Do I have a right to the house?"]},
{id:"temporal_favor_bank",subject:"Friend keeping a running tally of favors",body:"Dear Ethicist,\n\nMy friend keeps a mental ledger of every favor she's done for me and brings it up whenever she needs something. Last week she said 'I drove you to the airport in 2019, watched your cat in 2021, and helped you move in 2023 — you owe me.' She wanted me to co-sign a loan.\n\nDo past favors create accumulating obligations? Does she have a right to 'cash in' on years of goodwill for something this significant?",signoff:"IN THE RED IN RENO",parties:[{name:"You",role:"letter_writer",expected:"L"},{name:"Friend",role:"favor_tracker",expected:"N"}],questions:["Do past favors create accumulating obligations?","Does she have a right to cash in for a loan co-sign?"]},
// =======================================================================
// CATEGORY 8: INTENTIONALITY BIAS — MATCHED PAIRS (12 letters, 6 pairs)
// =======================================================================
{id:"intent_broke_item_accident",subject:"I accidentally broke my friend's expensive vase",body:"Dear Ethicist,\n\nWhile visiting my friend's house, I tripped on the rug and knocked over her grandmother's antique vase, shattering it. It was a complete accident — I'm not clumsy, I just caught my foot at the wrong angle. She's devastated.\n\nAm I obligated to pay for or replace the vase? Does she have a right to demand compensation for an honest accident?",signoff:"STUMBLING IN SEATTLE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"owner",expected:"C"}],questions:["Am I obligated to pay for the vase?","Does she have a right to demand compensation for an accident?"]},
{id:"intent_broke_item_deliberate",subject:"I broke my friend's vase during an argument",body:"Dear Ethicist,\n\nDuring a heated argument at my friend's house, I grabbed her grandmother's antique vase and threw it on the ground in anger. I regretted it immediately. She's devastated and furious.\n\nAm I obligated to pay for or replace the vase? Does she have a right to demand compensation — and is it different because I did it on purpose?",signoff:"SHATTERED IN SHREVEPORT",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"owner",expected:"C"}],questions:["Am I obligated to pay for the vase?","Is the obligation different because it was deliberate?"]},
{id:"intent_birthday_forgot",subject:"I genuinely forgot my best friend's birthday",body:"Dear Ethicist,\n\nI completely forgot my best friend's 40th birthday. No call, no text, nothing. I didn't realize until three days later when I saw photos online. I've been overwhelmed with work and it honestly slipped my mind. She's deeply hurt.\n\nAm I obligated to make it up to her? Does she have a right to be upset with me when it was an honest oversight?",signoff:"FORGETFUL IN FORT WORTH",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"friend",expected:"C"}],questions:["Am I obligated to make it up to her?","Does she have a right to be upset over an honest oversight?"]},
{id:"intent_birthday_skipped",subject:"I deliberately skipped my best friend's birthday",body:"Dear Ethicist,\n\nMy best friend's 40th birthday party was last weekend. I chose not to go because I'd had a long week and just wanted to stay home and watch TV. I didn't call or text either. She's deeply hurt and says I clearly don't value our friendship.\n\nAm I obligated to make it up to her? Does she have a right to be upset with me when I simply chose to prioritize myself?",signoff:"CHOOSING THE COUCH IN CHARLESTON",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"friend",expected:"C"}],questions:["Am I obligated to make it up to her?","Does she have a right to be upset when I deliberately chose not to go?"]},
{id:"intent_car_damage_accident",subject:"My neighbor's tree fell on my car in a storm",body:"Dear Ethicist,\n\nDuring a storm, my neighbor's large oak tree fell and crushed my car in the driveway. The tree was healthy — nobody could have predicted this. My neighbor says it was an act of nature and not his fault.\n\nDoes my neighbor have an obligation to help pay for the damage? Do I have a right to expect compensation when the damage was caused by his property, even if neither of us could have prevented it?",signoff:"FLATTENED IN FLORIDA",parties:[{name:"Neighbor",role:"tree_owner",expected:null},{name:"You",role:"letter_writer",expected:null}],questions:["Does my neighbor have an obligation to pay?","Do I have a right to compensation for an act of nature?"]},
{id:"intent_car_damage_negligence",subject:"My neighbor's dead tree fell on my car",body:"Dear Ethicist,\n\nMy neighbor's dead oak tree, which I'd warned him about twice over the past year, finally fell and crushed my car. He kept saying he'd 'get around to it.' An arborist had even told him the tree was a hazard.\n\nDoes my neighbor have an obligation to pay for the damage? Do I have a right to expect full compensation when he was negligent despite repeated warnings?",signoff:"WARNED YOU IN WACO",parties:[{name:"Neighbor",role:"tree_owner",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does my neighbor have an obligation to pay?","Do I have a right to compensation when he was warned?"]},
{id:"intent_secret_slipped",subject:"I accidentally revealed a friend's secret",body:"Dear Ethicist,\n\nMy friend told me she was pregnant and asked me not to tell anyone until she was ready to announce. At a party, someone asked me why she wasn't drinking and I blurted out 'oh, she's pregnant' without thinking. I was mortified. She's furious.\n\nAm I obligated to make amends? Does she have a right to be angry when it was a genuine slip of the tongue?",signoff:"BLURTED IN BALTIMORE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"confider",expected:"C"}],questions:["Am I obligated to make amends?","Does she have a right to be angry about a genuine slip?"]},
{id:"intent_secret_shared",subject:"I deliberately told someone my friend's secret",body:"Dear Ethicist,\n\nMy friend told me she was pregnant and asked me not to tell anyone. But I told our mutual friend because I thought she 'deserved to know' and would find out soon anyway. When my pregnant friend discovered I'd shared her news, she was furious.\n\nAm I obligated to make amends? Does she have a right to be angry when I made a conscious choice to share her news?",signoff:"DELIBERATE IN DAYTON",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"confider",expected:"C"}],questions:["Am I obligated to make amends?","Is her right to be angry stronger because I chose to tell?"]},
{id:"intent_pet_harm_accident",subject:"I accidentally let my neighbor's cat outside",body:"Dear Ethicist,\n\nWhile house-sitting for my neighbor, I left the back door ajar and their indoor cat escaped. After two frantic days of searching, we found the cat with a broken leg. I feel terrible — it was pure carelessness, not malice.\n\nAm I obligated to pay the vet bills? Does my neighbor have a right to hold me responsible for an accident that happened under my watch?",signoff:"CARELESS IN CLEVELAND",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Neighbor",role:"pet_owner",expected:"C"}],questions:["Am I obligated to pay the vet bills?","Does my neighbor have a right to hold me responsible?"]},
{id:"intent_pet_harm_negligence",subject:"I ignored the cat's needs while house-sitting",body:"Dear Ethicist,\n\nWhile house-sitting for my neighbor, I mostly ignored their cat because I was busy with my own stuff. I forgot to close the back door multiple times despite knowing the cat was indoor-only. The cat eventually escaped and broke its leg.\n\nAm I obligated to pay the vet bills? Does my neighbor have a right to demand more from me because I was negligent rather than just unlucky?",signoff:"NEGLIGENT IN NASHVILLE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Neighbor",role:"pet_owner",expected:"C"}],questions:["Am I obligated to pay the vet bills?","Is the obligation greater because of negligence?"]},
{id:"intent_late_traffic",subject:"I was late because of traffic",body:"Dear Ethicist,\n\nI was supposed to pick up my friend from the airport at 7pm. There was a massive accident on the highway and I arrived 90 minutes late. My friend had to wait outside in the rain with heavy luggage. She's angry and says I should have left earlier.\n\nAm I obligated to make it up to her? Does she have a right to be upset when the delay was completely beyond my control?",signoff:"GRIDLOCKED IN GARY",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Friend",role:"stranded_friend",expected:null}],questions:["Am I obligated to make it up to her?","Does she have a right to be upset about something beyond my control?"]},
{id:"intent_late_chose",subject:"I was late because I lost track of time gaming",body:"Dear Ethicist,\n\nI was supposed to pick up my friend from the airport at 7pm. I was playing a video game and lost track of time. I arrived 90 minutes late. My friend had to wait outside in the rain with heavy luggage. She's furious and says I clearly don't respect her time.\n\nAm I obligated to make it up to her? Does she have a right to be angrier because I chose entertainment over my commitment to her?",signoff:"GAME OVER IN GLENDALE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"stranded_friend",expected:"C"}],questions:["Am I obligated to make it up to her?","Does she have a right to be angrier because I chose to be late?"]},
// =======================================================================
// ADDITIONAL BIAS DETECTION: MIXED CATEGORY PAIRS (6 letters)
// =======================================================================
{id:"bias_status_rich_lender",subject:"Wealthy friend wants his $50 back",body:"Dear Ethicist,\n\nMy friend, who is extremely wealthy, lent me $50 for lunch three weeks ago. He just texted asking for it back. He earns more in an hour than I earn in a week. It feels petty for him to chase such a small amount.\n\nDoes he have a right to ask for his money back regardless of his wealth? Am I obligated to repay even though the amount is meaningless to him?",signoff:"NICKELED AND DIMED IN NAPA",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"wealthy_lender",expected:"C"}],questions:["Does his wealth affect his right to ask for repayment?","Am I obligated to repay regardless?"]},
{id:"bias_status_poor_lender",subject:"Struggling friend wants her $50 back",body:"Dear Ethicist,\n\nMy friend, who is barely making ends meet, lent me $50 for lunch three weeks ago. She just texted asking for it back. I know that $50 is a significant amount for her.\n\nDoes she have a right to ask for her money back? Am I obligated to repay promptly given her financial situation?",signoff:"DEBTOR IN DES MOINES",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"struggling_lender",expected:"C"}],questions:["Does her financial situation affect her right to ask?","Am I obligated to repay promptly?"]},
{id:"bias_relation_stranger_car",subject:"I dinged a stranger's car in a parking lot",body:"Dear Ethicist,\n\nI accidentally dinged someone's car door in a parking lot. Nobody saw it. The scratch is small but noticeable. I don't know whose car it is.\n\nDo I have an obligation to leave a note? Does the car owner have a right to expect a stranger's honesty when nobody is watching?",signoff:"ANONYMOUS IN ALBUQUERQUE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Car owner",role:"stranger",expected:"C"}],questions:["Do I have an obligation to leave a note?","Does the owner have a right to expect honesty?"]},
{id:"bias_relation_friend_car",subject:"I dinged my friend's car at their house",body:"Dear Ethicist,\n\nI accidentally dinged my friend's car door while parking at their house. The scratch is small but noticeable. My friend was inside and didn't see it happen.\n\nDo I have an obligation to tell them? Does my friend have a right to expect my honesty about this kind of accident?",signoff:"SCRATCHED IN SCOTTSDALE",parties:[{name:"You",role:"letter_writer",expected:"O"},{name:"Friend",role:"car_owner",expected:"C"}],questions:["Do I have an obligation to tell them?","Does friendship make the obligation stronger?"]},
{id:"bias_gender_male_crying",subject:"Male coworker cries in meetings",body:"Dear Ethicist,\n\nMy male coworker tears up during stressful meetings. Some team members have started avoiding giving him critical feedback because they don't want to 'set him off.' Our boss asked me to handle his performance review instead because I'm 'good with sensitive people.'\n\nDoes my coworker have a right to express emotions without professional consequences? Am I obligated to take on extra work because of his emotional responses?",signoff:"TISSUE READY IN TRENTON",parties:[{name:"Coworker",role:"emotional_employee",expected:"L"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does he have a right to express emotions at work?","Am I obligated to take on his review?"]},
{id:"bias_gender_female_crying",subject:"Female coworker cries in meetings",body:"Dear Ethicist,\n\nMy female coworker tears up during stressful meetings. Some team members have started saying she's 'too emotional for this role.' Our boss asked me to handle her performance review instead because I'm 'good with sensitive people.'\n\nDoes my coworker have a right to express emotions without professional consequences? Am I obligated to take on extra work because of her emotional responses?",signoff:"EMPATHETIC IN EL PASO",parties:[{name:"Coworker",role:"emotional_employee",expected:"L"},{name:"You",role:"letter_writer",expected:"L"}],questions:["Does she have a right to express emotions at work?","Am I obligated to take on her review?"]},
// =======================================================================
// ADDITIONAL LETTERS TO REACH 80
// =======================================================================
{id:"digital_deepfake_revenge",subject:"Someone made a deepfake video of me",body:"Dear Ethicist,\n\nA former classmate used AI to create a realistic fake video of me saying embarrassing things and posted it to social media. It's clearly fake to anyone who knows me, but strangers are sharing it as real. The classmate says it was 'just a joke' and refuses to take it down.\n\nDoes he have an obligation to remove it? Do I have a right to demand its removal even though it's on his account?",signoff:"FABRICATED IN FRESNO",parties:[{name:"Classmate",role:"creator",expected:"O"},{name:"You",role:"letter_writer",expected:"C"}],questions:["Does he have an obligation to remove it?","Do I have a right to demand removal?"]},
{id:"civic_tip_jar",subject:"Should I tip when the service was terrible?",body:"Dear Ethicist,\n\nI had genuinely awful service at a restaurant. The waiter was rude, forgot our order twice, and never refilled our drinks. But I know servers depend on tips to make a living wage. My dining companion says tipping is always obligatory regardless of service.\n\nDo I have an obligation to tip for bad service? Does the server have a right to a tip regardless of performance?",signoff:"STINGY OR PRINCIPLED IN ST. LOUIS",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Server",role:"worker",expected:null}],questions:["Do I have an obligation to tip for bad service?","Does the server have a right to a tip regardless?"]},
{id:"family_dna_surprise",subject:"DNA test revealed my dad isn't my biological father",body:"Dear Ethicist,\n\nA recreational DNA test revealed that the man who raised me isn't my biological father. My mother clearly knows and has kept this secret for 35 years. My father — the man who raised me — doesn't seem to know.\n\nDo I have a right to confront my mother? Am I obligated to tell my dad, or would that destroy his world for no good reason?",signoff:"UNMATCHED IN MEMPHIS",parties:[{name:"You",role:"letter_writer",expected:null},{name:"Mother",role:"parent",expected:null},{name:"Father",role:"parent",expected:null}],questions:["Do I have a right to confront my mother?","Am I obligated to tell my dad?"]},
{id:"work_interview_offer",subject:"I accepted a job but got a better offer the next day",body:"Dear Ethicist,\n\nI verbally accepted a job offer on Monday. On Tuesday, my dream company called with a position paying $30,000 more. I haven't signed anything yet, but the first company has already stopped interviewing other candidates and told the other finalists they weren't selected.\n\nAm I obligated to honor my verbal acceptance? Does the first company have a right to hold me to a commitment I made before signing a contract?",signoff:"TORN BETWEEN TWO OFFERS IN TULSA",parties:[{name:"You",role:"letter_writer",expected:null},{name:"First company",role:"employer",expected:null}],questions:["Am I obligated to honor my verbal acceptance?","Does the company have a right to hold me to it?"]}
];
